/**
 * Create a typed query key factory for a resource
 *
 * @example
 * ```typescript
 * const postKeys = createQueryKeyFactory('posts');
 *
 * // All posts
 * postKeys.all() // ['posts']
 *
 * // Posts list
 * postKeys.lists() // ['posts', 'list']
 *
 * // Posts list with filters
 * postKeys.list({ status: 'published' }) // ['posts', 'list', { status: 'published' }]
 *
 * // Single post detail
 * postKeys.detail(123) // ['posts', 'detail', 123]
 * ```
 */
export declare function createQueryKeyFactory(resource: string): {
    /**
     * All queries for this resource
     */
    all: () => readonly [string];
    /**
     * All list queries for this resource
     */
    lists: () => readonly [string, "list"];
    /**
     * List query with optional filters
     */
    list: (filters?: Record<string, unknown>) => readonly [string, "list"] | readonly [string, "list", Record<string, unknown>];
    /**
     * All detail queries for this resource
     */
    details: () => readonly [string, "detail"];
    /**
     * Detail query for specific item
     */
    detail: (id: string | number) => readonly [string, "detail", string | number];
    /**
     * Custom query key
     */
    custom: (...args: unknown[]) => readonly [string, ...unknown[]];
};
